const response = $input.item.json;

if (response.success && response.data) {
  const followups = response.data.leads;

  // Sort by priority score descending, then by days overdue descending
  followups.sort((a, b) => {
    if (b.priority_score !== a.priority_score) {
      return b.priority_score - a.priority_score;
    }
    return b.days_overdue - a.days_overdue;
  });

  return [{
    json: {
      success: true,
      total_leads: response.data.total_leads,
      overdue_count: response.data.overdue_count,
      due_today_count: response.data.due_today_count,
      due_this_week_count: response.data.due_this_week_count,
      call_list: followups,
      message: `Generated call list with ${followups.length} leads`
    }
  }];
} else {
  return [{
    json: {
      success: false,
      error: response.message || 'Failed to fetch follow-ups'
    }
  }];
}

const data = $input.item.json;

if (!data.success) {
  return [{ json: { error: data.error } }];
}

const callList = data.call_list;

// Generate readable summary
let summary = `DAILY CALL LIST\n`;
summary += `================\n`;
summary += `Total Leads: ${data.total_leads}\n`;
summary += `Overdue: ${data.overdue_count}\n`;
summary += `Due Today: ${data.due_today_count}\n`;
summary += `Due This Week: ${data.due_this_week_count}\n\n`;

summary += `PRIORITY CALL LIST\n`;
summary += `==================\n\n`;

callList.forEach((lead, index) => {
  const priority = lead.priority_label.toUpperCase();
  const overdue = lead.days_overdue > 0 ? ` (${lead.days_overdue}d overdue)` : '';

  summary += `${index + 1}. [${priority}]${overdue} ${lead.contact_name}\n`;
  summary += `   Company: ${lead.company_name}\n`;
  summary += `   Score: ${lead.priority_score}\n`;
  summary += `   Status: ${lead.status}\n`;
  summary += `   Follow-up: ${lead.next_followup_at}\n`;
  summary += `   Last Contact: ${lead.last_contacted_at || 'Never'}\n\n`;
});

return [{
  json: {
    summary: summary,
    call_list: callList,
    stats: {
      total: data.total_leads,
      overdue: data.overdue_count,
      due_today: data.due_today_count,
      due_this_week: data.due_this_week_count
    }
  }
}];
